mapper.select:
SELECT COUNT(1)
FROM room
WHERE unit_id = #{unitId}
  AND room_no = #{roomNo}
  AND deleted = 0

  AND id != #{excludeId}

SELECT r.id, r.building_id, b.name AS building_name, r.unit_id, bu.name AS unit_name, r.room_no, r.floor_no, r.area, r.price, r.cover, r.images, r.layout, r.orientation, r.decoration, r.status, r.remark, r.create_time FROM room r INNER JOIN building b ON r.building_id = b.id AND b.deleted = 0 INNER JOIN building_unit bu ON r.unit_id = bu.id AND bu.deleted = 0 WHERE r.deleted = 0
AND r.building_id = #{buildingId}
AND r.unit_id = #{unitId}
AND r.floor_no = #{floorNo}
AND r.room_no LIKE CONCAT('%', #{roomNo}, '%')
AND r.status = #{status}
ORDER BY r.building_id ASC, r.unit_id ASC, r.floor_no ASC, r.room_no ASC

SELECT r.id, r.building_id, b.name AS building_name, r.unit_id, bu.name AS unit_name, r.room_no, r.floor_no, r.area, r.price, r.cover, r.images, r.layout, r.orientation, r.decoration, r.status, r.remark, r.create_time FROM room r INNER JOIN building b ON r.building_id = b.id AND b.deleted = 0 INNER JOIN building_unit bu ON r.unit_id = bu.id AND bu.deleted = 0 WHERE r.deleted = 0
AND r.building_id = #{buildingId}
AND r.unit_id = #{unitId}
AND r.floor_no = #{floorNo}
AND r.room_no LIKE CONCAT('%', #{roomNo}, '%')
AND r.status = #{status}
ORDER BY r.building_id ASC, r.unit_id ASC, r.floor_no ASC, r.room_no ASC
